-- WORKS
DROP TABLE WORKS CASCADE;
CREATE TABLE WORKS (
  ID NVARCHAR(36) NOT NULL,
  createdAt TIMESTAMP,
  createdBy NVARCHAR(255),
  modifiedAt TIMESTAMP,
  modifiedBy NVARCHAR(255),
  status INTEGER,
  description NVARCHAR(100),
  responsibleType INTEGER,
  externalType INTEGER,
  internalResponsible NVARCHAR(100),
  externalResponsible NVARCHAR(100),
  comments NVARCHAR(1000),
  startDate TIMESTAMP,
  endDate TIMESTAMP,
  expectedStartDate TIMESTAMP,
  expectedEndDate TIMESTAMP,
  realStartDate TIMESTAMP,
  realEndDate TIMESTAMP,
  parentId NVARCHAR(36),
  parentType_ID INTEGER,
  type_ID INTEGER,
  PRIMARY KEY(ID)
) WITH ASSOCIATIONS (
  MANY TO ONE JOIN WORK_PARENT_TYPES AS parentType ON (parentType.ID = parentType_ID),
  MANY TO ONE JOIN BLOCK_HEAD AS block ON (block.BLOCK_ID = parentId),
  MANY TO MANY JOIN WF_DETAIL_DOCUMENTS AS documents ON (documents.WORK_ID = ID),
  MANY TO MANY JOIN DOCUMENTS_PER_BLOCK AS approvalFlows ON (approvalFlows.WORK_ID = ID),
  MANY TO ONE JOIN WORK_TYPES AS type ON (type.ID = type_ID)
);

